import { useState, useCallback } from 'react';
import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: userApiKey, dangerouslyAllowBrowser: true });

export function useStreaming() {
  const [text, setText] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const stream = useCallback(async (prompt: string) => {
    setText('');
    setError(null);
    setIsStreaming(true);

    try {
      const s = await client.messages.stream({
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 1024,
        messages: [{ role: 'user', content: prompt }],
      });

      for await (const chunk of s) {
        if (
          chunk.type === 'content_block_delta' &&
          chunk.delta.type === 'text_delta'
        ) {
          // Functional update avoids stale closure issues
          setText((prev) => prev + chunk.delta.text);
        }
      }
    } catch (e) {
      if ((e as Error).name !== 'AbortError') {
        setError(String(e));
      }
    } finally {
      setIsStreaming(false);
    }
  }, []);

  return { text, isStreaming, error, stream };
}

import { useRef, useState, useCallback } from 'react';

export function useStreamingBuffered(flushMs = 50) {
  const [text, setText] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const buffer = useRef('');
  const flushTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  function scheduleFlush() {
    if (flushTimer.current) return;
    flushTimer.current = setTimeout(() => {
      setText(buffer.current);
      flushTimer.current = null;
    }, flushMs);
  }

  const stream = useCallback(async (prompt: string, client: Anthropic) => {
    buffer.current = '';
    setText('');
    setIsStreaming(true);

    try {
      const s = await client.messages.stream({
        model: 'claude-haiku-4-5-20251001',
        max_tokens: 1024,
        messages: [{ role: 'user', content: prompt }],
      });

      for await (const chunk of s) {
        if (chunk.type === 'content_block_delta' && chunk.delta.type === 'text_delta') {
          buffer.current += chunk.delta.text;
          scheduleFlush();
        }
      }

      // Final flush — ensure last tokens appear
      if (flushTimer.current) clearTimeout(flushTimer.current);
      setText(buffer.current);
    } finally {
      setIsStreaming(false);
    }
  }, [flushMs]);

  return { text, isStreaming, stream };
}

import { useRef, useState, useCallback, useEffect } from 'react';
import Anthropic from '@anthropic-ai/sdk';

const client = new Anthropic({ apiKey: userApiKey, dangerouslyAllowBrowser: true });

export function useCancellableStream() {
  const [text, setText] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const controllerRef = useRef<AbortController | null>(null);

  // Cancel when component unmounts
  useEffect(() => () => { controllerRef.current?.abort(); }, []);

  const start = useCallback(async (prompt: string) => {
    // Cancel any in-flight stream before starting a new one
    controllerRef.current?.abort();
    const controller = new AbortController();
    controllerRef.current = controller;

    setText('');
    setIsStreaming(true);

    try {
      const s = await client.messages.stream(
        {
          model: 'claude-haiku-4-5-20251001',
          max_tokens: 1024,
          messages: [{ role: 'user', content: prompt }],
        },
        { signal: controller.signal }  // pass the signal as a request option
      );

      for await (const chunk of s) {
        if (chunk.type === 'content_block_delta' && chunk.delta.type === 'text_delta') {
          setText((prev) => prev + chunk.delta.text);
        }
      }
    } catch (e) {
      if ((e as Error).name === 'AbortError') return;  // expected — user cancelled
      console.error('Stream error:', e);
    } finally {
      setIsStreaming(false);
    }
  }, []);

  const stop = useCallback(() => {
    controllerRef.current?.abort();
  }, []);

  return { text, isStreaming, start, stop };
}

import { useRef, useState } from 'react';
import {
  Button, KeyboardAvoidingView, Platform,
  ScrollView, StyleSheet, Text, TextInput, View,
} from 'react-native';
import { useCancellableStream } from '../hooks/useCancellableStream';

export default function ChatScreen() {
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: string; content: string }[]>([]);
  const { text, isStreaming, start, stop } = useCancellableStream();
  const scrollRef = useRef<ScrollView>(null);

  async function send() {
    if (!input.trim() || isStreaming) return;
    const userMsg = { role: 'user', content: input };
    setMessages((prev) => [...prev, userMsg]);
    setInput('');
    await start(input);
    // After stream completes, add assistant turn to history
    setMessages((prev) => [...prev, { role: 'assistant', content: text }]);
  }

  return (
    <KeyboardAvoidingView
      style={{ flex: 1 }}
      behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
    >
      <ScrollView
        ref={scrollRef}
        style={styles.messages}
        onContentSizeChange={() => scrollRef.current?.scrollToEnd({ animated: true })}
      >
        {messages.map((m, i) => (
          <View key={i} style={[styles.bubble, m.role === 'user' ? styles.user : styles.assistant]}>
            <Text>{m.content}</Text>
          </View>
        ))}
        {isStreaming && (
          <View style={styles.assistant}>
            <Text>{text}<Text style={styles.cursor}>|</Text></Text>
          </View>
        )}
      </ScrollView>
      <View style={styles.inputRow}>
        <TextInput
          style={styles.input}
          value={input}
          onChangeText={setInput}
          placeholder="Message..."
          editable={!isStreaming}
        />
        {isStreaming
          ? <Button title="Stop" onPress={stop} color="#dc2626" />
          : <Button title="Send" onPress={send} />}
      </View>
    </KeyboardAvoidingView>
  );
}

const styles = StyleSheet.create({
  messages: { flex: 1, padding: 12 },
  bubble: { marginBottom: 8, padding: 10, borderRadius: 12, maxWidth: '85%' },
  user: { backgroundColor: '#dbeafe', alignSelf: 'flex-end' },
  assistant: { backgroundColor: '#f3f4f6', alignSelf: 'flex-start' },
  cursor: { opacity: 0.5 },
  inputRow: { flexDirection: 'row', padding: 8, gap: 8, borderTopWidth: 1, borderColor: '#e5e7eb' },
  input: { flex: 1, borderWidth: 1, borderColor: '#d1d5db', borderRadius: 8, paddingHorizontal: 12, paddingVertical: 8 },
});

const s = await client.messages.stream({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  messages: [{ role: 'user', content: prompt }],
});

// Fires for every text delta
s.on('text', (textDelta) => {
  setText((prev) => prev + textDelta);
});

// Fires when content block starts/ends
s.on('content_block_start', (event) => {
  console.log('Block started:', event.content_block.type);
});

// Fires once when the stream ends
s.on('finalMessage', (message) => {
  console.log('Usage:', message.usage);
  setIsStreaming(false);
});

// Error handling
s.on('error', (e) => {
  if (e.name !== 'AbortError') setError(String(e));
  setIsStreaming(false);
});
